static void
mark_context_stack(mrb_state *mrb, struct mrb_context *c)
{
  size_t i, e;
  mrb_value nil;

  if (c->stbase == NULL) return;
  if (c->ci) {
    e = (c->ci->stack ? c->ci->stack - c->stbase : 0);
    e += mrb_ci_nregs(c->ci);
  }
  else {
    e = 0;
  }
  if (c->stbase + e > c->stend) e = c->stend - c->stbase;
  for (i=0; i<e; i++) {
    mrb_value v = c->stbase[i];

    if (!mrb_immediate_p(v)) {
      mrb_gc_mark(mrb, mrb_basic_ptr(v));
    }
  }
  e = c->stend - c->stbase;
  nil = mrb_nil_value();
  for (; i<e; i++) {
    c->stbase[i] = nil;
  }
}

static void attr_free(zval *v)
{
        zend_attribute *attr = Z_PTR_P(v);
        bool persistent = attr->flags & ZEND_ATTRIBUTE_PERSISTENT;

        zend_string_release(attr->name);
        zend_string_release(attr->lcname);

        for (uint32_t i = 0; i < attr->argc; i++) {
                if (attr->args[i].name) {
                        zend_string_release(attr->args[i].name);
                }
                if (persistent) {
                        zval_internal_ptr_dtor(&attr->args[i].value);
                } else {
                        zval_ptr_dtor(&attr->args[i].value);
                }
        }

        pefree(attr, persistent);
}
